      {{- with .Values.crowd.securityContext }}
      securityContext:
        {{ toYaml . | nindent 8 }}
        {{- if not .fsGroup }}
        fsGroup: 2004
        {{- end }}
      {{- end }}
      {{- end }}
      {{- end }}
      initContainers:
        {{- include "crowd.additionalInitContainers" . | nindent 8 }}
        {{- if and .Values.volumes.sharedHome.nfsPermissionFixer.enabled (not .Values.openshift.runWithRestrictedSCC) }}
